mapper.select:

		SELECT A.CODE_ID codeId, B.CODE_ID_NM codeIdNm, A.CODE code, A.CODE_NM codeNm, A.CODE_DC codeDc, A.USE_AT useAt
		FROM acm_code_sub A, acm_code_mst B
        WHERE B.USE_AT = 'Y'
        AND A.CODE_ID = B.CODE_ID
		AND A.CODE_ID = #{codeId}
        AND  A.CODE    = #{code}

mapper.insert:

		INSERT INTO  acm_code_sub(
			CODE_ID, CODE, CODE_NM, CODE_DC, USE_AT, FRST_REGIST_PNTTM, FRST_REGISTER_ID, LAST_UPDT_PNTTM, LAST_UPDUSR_ID
        ) VALUES (
         	#{codeId}, #{code}, #{codeNm}, #{codeDc}, #{useAt}, sysdate(), #{frstRegisterId}, sysdate(), #{frstRegisterId}
        )

mapper.update:

		UPDATE  acm_code_sub
        SET 
        	CODE_NM = #{codeNm}
        	, CODE_DC = #{codeDc}
        	, USE_AT = #{useAt}
        	, LAST_UPDT_PNTTM = sysdate()
        	, LAST_UPDUSR_ID = #{lastUpdusrId}
        WHERE CODE_ID = #{codeId}
        AND CODE = #{code}

mapper.delete:

		UPDATE acm_code_sub
        SET USE_AT = 'N'
        WHERE CODE_ID = #{codeId}
        AND CODE = #{code}
